public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    int maxLen = 0;

    public int longestZigZag(TreeNode root) {
        longestZigZagUtil(root, true);
        longestZigZagUtil(root, false);
        return maxLen;
    }

    private int longestZigZagUtil(TreeNode root, boolean left) {
        if (root == null)
            return -1;

        int leftZig = longestZigZagUtil(root.left, true);
        int rightZig = longestZigZagUtil(root.right, false);

        maxLen = Math.max(maxLen, Math.max(leftZig, rightZig) + 1);
        return left ? rightZig + 1 : leftZig + 1;
    }
}
```


